import{_ as a,c as i,o as t,ae as o}from"./chunks/framework.D4x4JNJ3.js";const h=JSON.parse('{"title":"Changelog v2026.1.x","description":"","frontmatter":{"title":"Changelog v2026.1.x"},"headers":[],"relativePath":"en/changelog/v2026.1.x.md","filePath":"en/changelog/v2026.1.x.md","lastUpdated":1772156751000}'),n={name:"en/changelog/v2026.1.x.md"};function s(l,e,r,d,c,g){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="mogan-stem-v2026-1-x-changelog" tabindex="-1">Mogan STEM v2026.1.x Changelog <a class="header-anchor" href="#mogan-stem-v2026-1-x-changelog" aria-label="Permalink to “Mogan STEM v2026.1.x Changelog”">​</a></h1><blockquote><p>Note: Liii STEM is the commercial edition of Mogan STEM. It provides value-added features on top of the open-source version, such as account login and AI. For more details, see Liii STEM: <a href="https://liiistem.com/docs/changelog-v2026.1.x.html" target="_blank" rel="">v2026.1.x</a></p></blockquote><h2 id="⭐️-new-features-highlights" tabindex="-1">⭐️ New Features &amp; Highlights <a class="header-anchor" href="#⭐️-new-features-highlights" aria-label="Permalink to “⭐️ New Features &amp; Highlights”">​</a></h2><ol><li><strong>Magic Paste improvements and (Liii STEM) Math OCR</strong>: Supports lossless pasting of webpages/conversations; (Liii STEM) recognizes formulas from images/screenshots/handwriting and PDFs, and quickly pastes them into Liii STEM format.</li><li><strong>Selective paste</strong>: Automatically detects clipboard formats and lets you paste Markdown / LaTeX / HTML as needed (<code>Ctrl</code> + <code>Alt</code> + <code>V</code> / <code>Command</code> + <code>Option</code> + <code>V</code>).</li><li><strong>(Liii STEM) AI model expansion</strong>: Added GLM-4.6V and Kimi-K2.5 models to improve AI-assisted writing and chat.</li><li><strong>Enhanced table capabilities</strong>: Drag table inner grid lines; added three-line tables for more efficient table typesetting.</li><li><strong>Structured find/replace</strong>: Find and replace structured content such as text, formulas, symbols, and matrices.</li><li><strong>New comments</strong>: Added a “Comments” menu; supports foldable comments in documents; comment content supports text and formulas.</li><li><strong>Code syntax highlighting</strong>: Added syntax highlighting for R / SQL / Bash.</li><li><strong>Academic writing support</strong>: Bibliography style supports GBT7714-2015.</li></ol><h2 id="🌟-summary" tabindex="-1">🌟 Summary <a class="header-anchor" href="#🌟-summary" aria-label="Permalink to “🌟 Summary”">​</a></h2><p>Mogan STEM v2026.1.x continues to refine <strong>Magic Paste</strong>: selective paste for Markdown/LaTeX/HTML, better tables (drag grid lines, three-line tables), improved structured find/replace and comments, plus more syntax highlighting and GBT7714-2015 bibliography support with various stability fixes. Liii STEM builds on top of this with value-added features such as Math OCR and AI models.</p><h2 id="🔧-release-notes" tabindex="-1">🔧 Release Notes <a class="header-anchor" href="#🔧-release-notes" aria-label="Permalink to “🔧 Release Notes”">​</a></h2><h3 id="mogan-stem-v2026-1-2-2026-01-23" tabindex="-1">Mogan STEM v2026.1.2 (2026/01/23) <a class="header-anchor" href="#mogan-stem-v2026-1-2-2026-01-23" aria-label="Permalink to “Mogan STEM v2026.1.2 (2026/01/23)”">​</a></h3><ol><li>Added SQL syntax highlighting.</li><li>Added Bash syntax highlighting.</li><li>Fixed Tab Cycling position issues when zooming.</li><li>Fixed tearing when rendering large square roots.</li></ol><h3 id="mogan-stem-v2026-1-1-2026-01-16" tabindex="-1">Mogan STEM v2026.1.1 (2026/01/16) <a class="header-anchor" href="#mogan-stem-v2026-1-1-2026-01-16" aria-label="Permalink to “Mogan STEM v2026.1.1 (2026/01/16)”">​</a></h3><ol><li>Magic Paste: improved lossless pasting from webpages/conversations; text mode supports image OCR (Liii STEM); math mode supports converting LaTeX to Mogan STEM.</li><li>Selective paste: choose Markdown / LaTeX / HTML formats; supports image OCR to formulas (Liii STEM).</li><li>Structured find/replace for text, formulas, symbols, and matrices.</li><li>New comments: fold/unfold comments; comment content supports text and formulas.</li><li>Night mode for both UI and documents.</li><li>Typesetting engine optimization: Chinese punctuation compression.</li><li>Tables: drag inner grid lines.</li><li>Tab Cycling: added <code>mathcal</code> / <code>mathbf</code> / <code>mathfrak</code> / <code>mathscr</code> / <code>mathbbm</code>, and <code>n</code> gets a <code>\\nabla</code> variant.</li><li>Image floating menu: quick layout adjustments and OCR (Liii STEM).</li><li><code>nbsp</code> display tweaks: non-breaking spaces use an invisible color by default and can be adjusted.</li><li>Added R syntax highlighting.</li><li>Bibliography style supports GBT7714-2015.</li></ol><h2 id="👏-join-us" tabindex="-1">👏 Join Us <a class="header-anchor" href="#👏-join-us" aria-label="Permalink to “👏 Join Us”">​</a></h2><ul><li>Mogan STEM Official Website: <a href="https://mogan.app/" target="_blank" rel="">https://mogan.app/</a></li><li>Mogan Community QQ Group: <a href="https://qun.qq.com/universal-share/share?ac=1&amp;authKey=NoxIHFT4nzWfHJnqGNQygmXt%2FhpydluCE%2FcF1qMzu1BHpNNjv7ZGZxWwS0fGx32Y&amp;busi_data=eyJncm91cENvZGUiOiI5MzQ0NTY5NzEiLCJ0b2tlbiI6InpOMGxCaHIvdEtyM1V1d0VGYlpTQThZZ2NDODQxUjU1dWdBZEF5cG9MUHptN3R6Q1NXenNaWVluOVpjOTd3VHAiLCJ1aW4iOiI3ODUyNTEzMjIifQ%3D%3D&amp;data=n9XWNwOuQOWPbezHFAHZS24nvSli9BNzrLjrfFr_JWfStSboc6G5DZwBXWzZDqXc5A29OptCvKgtVjZ1Gwmu1A&amp;svctype=4&amp;tempid=h5_group_info" target="_blank" rel="">934456971</a></li><li>Discord Group: <a href="https://discord.gg/Q7xARnAf8t" target="_blank" rel="">https://discord.gg/Q7xARnAf8t</a></li></ul>',13)])])}const p=a(n,[["render",s]]);export{h as __pageData,p as default};
